mapper.select:
SELECT id, user_id, memory_scope, topic_key, memory_type, content, content_summary, confidence_score, source_type, source_ref_id,
       is_pinned, is_deleted, last_hit_at, created_at, updated_at
FROM agent_memory
WHERE user_id = #{userId}
  AND (is_deleted = 0 OR is_deleted IS NULL)

    AND memory_scope = #{memoryScope}


    AND (
        LOWER(COALESCE(topic_key, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(COALESCE(content, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
    )


    AND is_pinned = 1

ORDER BY is_pinned DESC, created_at DESC
LIMIT #{offset}, #{limit}

SELECT id, user_id, memory_scope, topic_key, memory_type, content, content_summary, confidence_score, source_type, source_ref_id,
       is_pinned, is_deleted, last_hit_at, created_at, updated_at
FROM agent_memory
WHERE id = #{id}
  AND user_id = #{userId}
LIMIT 1

SELECT COUNT(1)
FROM agent_memory
WHERE user_id = #{userId}
  AND (is_deleted = 0 OR is_deleted IS NULL)

    AND memory_scope = #{memoryScope}


    AND (
        LOWER(COALESCE(topic_key, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        OR LOWER(COALESCE(content, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
    )


    AND is_pinned = 1

mapper.update:
UPDATE agent_memory
SET is_pinned = #{pinned},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE agent_memory
SET is_deleted = 1,
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE agent_memory
SET is_deleted = 0,
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}
